package config

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"gopkg.in/yaml.v3"
)

// RoutingMigrationError signals that the loaded config carries a removed
// agent.routing field. The field is gone for good; configs must be migrated
// before DDx will load them.
type RoutingMigrationError struct {
	Field string
	Path  string
}

func (e *RoutingMigrationError) Error() string {
	return fmt.Sprintf(
		"%s: %s has been removed. "+
			"Migration: delete the field from your .ddx/config.yaml. "+
			"See docs/migrations/routing-config.md.",
		e.Path, e.Field)
}

// checkRoutingMigration parses the raw config bytes and hard-errors on any
// removed agent.routing fields.
func checkRoutingMigration(path string, data []byte) error {
	var raw map[string]any
	if err := yaml.Unmarshal(data, &raw); err != nil {
		return nil // YAML errors surface from the validator below
	}
	agent, _ := raw["agent"].(map[string]any)
	if agent == nil {
		return nil
	}
	routing, _ := agent["routing"].(map[string]any)
	if routing == nil {
		return nil
	}
	// routinglint:legacy-rejection reason="hard-error rejection of retired routing keys per ddx-3bd7396a"
	for _, field := range []string{"default_harness", "profile_ladders", "model_overrides"} {
		if _, ok := routing[field]; ok {
			return &RoutingMigrationError{
				Field: "agent.routing." + field,
				Path:  path,
			}
		}
	}
	return nil
}

// Type aliases for smooth transition
type Config = NewConfig
type Repository = RepositoryConfig

// ConfigError represents a single configuration error
type ConfigError struct {
	Field      string
	Value      string
	Message    string
	Suggestion string
}

func (e *ConfigError) Error() string {
	return fmt.Sprintf("%s: %s", e.Field, e.Message)
}

// ValidationError represents multiple configuration errors
type ValidationError struct {
	Errors []*ConfigError
}

func (e *ValidationError) Error() string {
	if len(e.Errors) == 1 {
		return e.Errors[0].Error()
	}
	return fmt.Sprintf("%d configuration errors found", len(e.Errors))
}

// Load loads configuration using the new simplified approach
func Load() (*Config, error) {
	workingDir, err := os.Getwd()
	if err != nil {
		return nil, fmt.Errorf("failed to get working directory: %w", err)
	}
	return LoadWithWorkingDir(workingDir)
}

// LoadWithWorkingDir loads configuration from a specific working directory
func LoadWithWorkingDir(workingDir string) (*Config, error) {
	if workingDir == "" {
		var err error
		workingDir, err = os.Getwd()
		if err != nil {
			return nil, fmt.Errorf("failed to get working directory: %w", err)
		}
	}

	// Use the new ConfigLoader to load from .ddx/config.yaml only
	loader, err := NewConfigLoaderWithWorkingDir(workingDir)
	if err != nil {
		return nil, fmt.Errorf("failed to create config loader: %w", err)
	}

	// Pre-validation migration check: surface a friendly hard error for
	// removed agent.routing fields before the schema validator sees the file.
	// This happens before LoadConfig so the migration message is what the
	// operator sees.
	configPath := filepath.Join(workingDir, ".ddx", "config.yaml")
	if data, readErr := os.ReadFile(configPath); readErr == nil {
		if migErr := checkRoutingMigration(configPath, data); migErr != nil {
			return nil, migErr
		}
	}

	config, err := loader.LoadConfig()
	if err != nil {
		// If no config file exists, return default config
		if os.IsNotExist(err) || strings.Contains(err.Error(), "no configuration file found") {
			config = DefaultNewConfig()
		} else {
			return nil, err
		}
	}

	// Apply defaults to ensure complete configuration
	config.ApplyDefaults()
	if config.Agent != nil && config.Agent.Routing != nil &&
		len(config.Agent.Routing.ProfilePriority) > 0 {
		fmt.Fprintln(os.Stderr, "warning: agent.routing.profile_priority is deprecated and will be removed in a future version")
	}

	// Override library path with environment variable if set
	if envLibraryPath := os.Getenv("DDX_LIBRARY_BASE_PATH"); envLibraryPath != "" {
		config.Library.Path = envLibraryPath
	}

	// Validate the final configuration
	if err := config.Validate(); err != nil {
		return nil, fmt.Errorf("configuration validation failed: %w", err)
	}

	return config, nil
}

// Validate validates the configuration structure and values (simplified)
func (c *Config) Validate() error {
	var errors []*ConfigError

	// Validate version
	if c.Version == "" {
		errors = append(errors, &ConfigError{
			Field:      "version",
			Message:    "version is required",
			Suggestion: "add 'version: \"1.0\"' to your config",
		})
	}

	// Validate library configuration
	if c.Library != nil && c.Library.Repository != nil {
		if c.Library.Repository.URL == "" {
			errors = append(errors, &ConfigError{
				Field:      "library.repository.url",
				Message:    "library repository URL is required",
				Suggestion: "add a valid Git repository URL",
			})
		}

		if c.Library.Repository.Branch == "" {
			errors = append(errors, &ConfigError{
				Field:      "library.repository.branch",
				Message:    "library repository branch is required",
				Suggestion: "add 'branch: \"main\"' or another valid branch name",
			})
		}
	}

	if len(errors) > 0 {
		return &ValidationError{Errors: errors}
	}

	return nil
}

// Merge combines this config with another, with the other taking precedence
func (c *Config) Merge(other *Config) *Config {
	result := &Config{
		Version: c.Version,
	}

	// Copy library configuration from base
	if c.Library != nil {
		result.Library = &LibraryConfig{
			Path: c.Library.Path,
		}
		if c.Library.Repository != nil {
			result.Library.Repository = &RepositoryConfig{
				URL:    c.Library.Repository.URL,
				Branch: c.Library.Repository.Branch,
			}
		}
	}

	// Override with other's values
	if other.Version != "" {
		result.Version = other.Version
	}
	if other.Library != nil {
		if result.Library == nil {
			result.Library = &LibraryConfig{}
		}
		if other.Library.Path != "" {
			result.Library.Path = other.Library.Path
		}
		if other.Library.Repository != nil {
			if result.Library.Repository == nil {
				result.Library.Repository = &RepositoryConfig{}
			}
			if other.Library.Repository.URL != "" {
				result.Library.Repository.URL = other.Library.Repository.URL
			}
			if other.Library.Repository.Branch != "" {
				result.Library.Repository.Branch = other.Library.Repository.Branch
			}
		}
	}

	return result
}

// ResolveLibraryResource resolves a library resource path
// NOTE: This function is now legacy. New code should load config and use cfg.Library.Path directly.
func ResolveLibraryResource(resourcePath, configPath, workingDir string) (string, error) {
	// Load config to get the authoritative library path (which includes env var override)
	cfg, err := LoadWithWorkingDir(workingDir)
	if err == nil && cfg.Library != nil && cfg.Library.Path != "" {
		// Check if it's an absolute path
		if filepath.IsAbs(resourcePath) {
			return resourcePath, nil
		}

		// Try relative to library path from config
		configPath := filepath.Join(cfg.Library.Path, resourcePath)
		if _, err := os.Stat(configPath); err == nil {
			return configPath, nil
		}

		// Return the config path even if it doesn't exist (for consistency)
		return configPath, nil
	}

	// Fall back to original logic if config loading fails
	if workingDir == "" {
		workingDir, err = os.Getwd()
		if err != nil {
			return "", err
		}

package config

import (
	"fmt"
	"os"
	"path/filepath"
	"sync"

	"gopkg.in/yaml.v3"
)

var configReachabilityOnce sync.Once

func anchorConfigReachability() {
	configReachabilityOnce.Do(func() {
		_, _ = NewConfigLoader()

		tmpDir, err := os.MkdirTemp("", "ddx-config-anchor-*")
		if err == nil {
			defer func() {
				_ = os.RemoveAll(tmpDir)
			}()

			_, _ = NewConfigLoaderWithWorkingDir(tmpDir)
			loader := &ConfigLoader{workingDir: tmpDir}
			_, _, _ = loader.DetectConfigFormat()
			_, _ = ResolveLibraryResource("anchor.md", "", tmpDir)
		}

		_ = NewTestConfigForLoop(TestLoopConfigOpts{})
		_ = NewTestConfigForRun(TestRunConfigOpts{})
		_ = NewTestConfigForBead(TestBeadConfigOpts{})
		_ = TestBeadOverrides(TestBeadConfigOpts{})
		_ = TestLoopOverrides(TestLoopConfigOpts{})
	})
}

// ConfigLoader handles loading configuration files with validation
type ConfigLoader struct {
	validator  Validator
	workingDir string
}

// NewConfigLoader creates a new configuration loader with validation
func NewConfigLoader() (*ConfigLoader, error) {
	workingDir, err := os.Getwd()
	if err != nil {
		return nil, fmt.Errorf("failed to get working directory: %w", err)
	}
	return NewConfigLoaderWithWorkingDir(workingDir)
}

// NewConfigLoaderWithWorkingDir creates a new configuration loader with a specific working directory
func NewConfigLoaderWithWorkingDir(workingDir string) (*ConfigLoader, error) {
	validator, err := NewValidator()
	if err != nil {
		return nil, fmt.Errorf("failed to create validator: %w", err)
	}

	return &ConfigLoader{
		validator:  validator,
		workingDir: workingDir,
	}, nil
}

// LoadConfig loads configuration from .ddx/config.yaml only
func (cl *ConfigLoader) LoadConfig() (*NewConfig, error) {
	// Only support new format: .ddx/config.yaml
	configPath := filepath.Join(cl.workingDir, ".ddx", "config.yaml")
	if _, err := os.Stat(configPath); err != nil {
		return nil, fmt.Errorf("no configuration file found at %s", configPath)
	}

	return cl.loadNewFormat(configPath)
}

// LoadConfigFromPath loads configuration from a specific path (new format only)
func (cl *ConfigLoader) LoadConfigFromPath(path string) (*NewConfig, error) {
	// Convert relative path to absolute based on working directory
	if !filepath.IsAbs(path) {
		path = filepath.Join(cl.workingDir, path)
	}

	return cl.loadNewFormat(path)
}

// loadNewFormat loads and validates the new configuration format
func (cl *ConfigLoader) loadNewFormat(path string) (*NewConfig, error) {
	// Read file
	data, err := os.ReadFile(path)
	if err != nil {
		return nil, fmt.Errorf("failed to read config file %s: %w", path, err)
	}

	// Validate using two-phase validation
	if err := cl.validator.Validate(data); err != nil {
		return nil, fmt.Errorf("configuration validation failed: %w", err)
	}

	// Parse YAML into new config structure
	var config NewConfig
	if err := yaml.Unmarshal(data, &config); err != nil {
		return nil, fmt.Errorf("failed to parse config YAML from %s: %w", path, err)
	}

	// Apply defaults to missing fields
	config.ApplyDefaults()

	return &config, nil
}

// SaveConfig saves configuration in the new format
func (cl *ConfigLoader) SaveConfig(config *NewConfig, path string) error {
	// Convert relative path to absolute based on working directory
	if !filepath.IsAbs(path) {
		path = filepath.Join(cl.workingDir, path)
	}

	// Create directory if it doesn't exist
	dir := filepath.Dir(path)
	if err := os.MkdirAll(dir, 0755); err != nil {
		return fmt.Errorf("failed to create config directory %s: %w", dir, err)
	}

	// Marshal to YAML
	data, err := yaml.Marshal(config)
	if err != nil {
		return fmt.Errorf("failed to marshal config: %w", err)
	}

	// Validate before saving
	if err := cl.validator.Validate(data); err != nil {
		return fmt.Errorf("config validation failed before save: %w", err)
	}

	// Write file with secure permissions
	if err := os.WriteFile(path, data, 0644); err != nil {
		return fmt.Errorf("failed to write config file %s: %w", path, err)
	}

	return nil
}

// DetectConfigFormat determines if .ddx/config.yaml exists in working directory
func (cl *ConfigLoader) DetectConfigFormat() (string, string, error) {
	configPath := filepath.Join(cl.workingDir, ".ddx", "config.yaml")
	if _, err := os.Stat(configPath); err == nil {
		return "new", configPath, nil
	}

	return "none", "", fmt.Errorf("no configuration file found at %s", configPath)
}

package config

import "time"

// TestLoopConfigOpts names every durable knob the execute-bead loop
// reads via ResolvedConfig. Tests must specify each field explicitly;
// there are no zero-value defaults that silently bypass real config.
//
// See SD-024 / TD-024 §Test config constructors.
type TestLoopConfigOpts struct {
	Assignee                           string
	ReviewMaxRetries                   int
	NoProgressCooldown                 time.Duration
	MaxNoChangesBeforeClose            int
	HeartbeatInterval                  time.Duration
	Harness                            string
	Model                              string
	Profile                            string
	MinTier                            string
	MaxTier                            string
	BeadQualityLintBlockThresholdScore int
	EvidenceCaps                       EvidenceCapsConfig
}

// NewTestConfigForLoop returns a *Config that, when Resolve()d with the
// matching CLIOverrides, produces a ResolvedConfig whose loop-relevant
// accessors return exactly the values supplied in opts.
//
// Tests must obtain ResolvedConfig via Resolve on the returned *Config
// — there is no shortcut to construct a ResolvedConfig directly. Pure
// CLI-override fields (Assignee, Profile, MinTier, MaxTier) are passed
// through CLIOverrides at the call site; the constructor stores every
// other field on *Config so it round-trips through Resolve.
func NewTestConfigForLoop(opts TestLoopConfigOpts) *Config {
	reviewMaxRetries := opts.ReviewMaxRetries
	maxNoChanges := opts.MaxNoChangesBeforeClose
	lintBlockThreshold := opts.BeadQualityLintBlockThresholdScore

	caps := opts.EvidenceCaps

	return &Config{
		Version: "1.0",
		BeadQuality: &BeadQualityConfig{
			Lint: &BeadQualityLintConfig{
				BlockThresholdScore: &lintBlockThreshold,
			},
		},
		Agent: &AgentConfig{
			Harness: opts.Harness,
			Model:   opts.Model,
		},
		Workers: &WorkersConfig{
			NoProgressCooldown:      opts.NoProgressCooldown.String(),
			MaxNoChangesBeforeClose: &maxNoChanges,
			HeartbeatInterval:       opts.HeartbeatInterval.String(),
		},
		ReviewMaxRetries: &reviewMaxRetries,
		EvidenceCaps:     &caps,
	}
}

// TestRunConfigOpts names every durable knob the agent run path reads
// via ResolvedConfig (per SD-024 §RunArgs → AgentRunRuntime field
// classification). Tests must specify each field explicitly; there are
// no zero-value defaults that silently bypass real config.
//
// See SD-024 / TD-024 §Test config constructors and §Stage 2 bead 17.
type TestRunConfigOpts struct {
	Harness       string
	Model         string
	Provider      string
	ModelRef      string
	Effort        string
	Permissions   string
	Timeout       time.Duration
	WallClock     time.Duration
	SessionLogDir string
}

// NewTestConfigForRun returns a *Config that, when Resolve()d with the
// matching CLIOverrides, produces a ResolvedConfig whose run-path
// accessors return the values supplied in opts. Pure CLI-override
// fields (Provider, ModelRef, Effort) have no durable home on
// AgentConfig and must be applied at Resolve time via CLIOverrides.
func NewTestConfigForRun(opts TestRunConfigOpts) *Config {
	return &Config{
		Version: "1.0",
		Agent: &AgentConfig{
			Harness:       opts.Harness,
			Model:         opts.Model,
			TimeoutMS:     int(opts.Timeout / time.Millisecond),
			SessionLogDir: opts.SessionLogDir,
			Permissions:   opts.Permissions,
		},
	}
}

// TestBeadConfigOpts names every durable knob the execute-bead worker
// reads via ResolvedConfig (per SD-024 §ExecuteBeadOptions →
// ExecuteBeadRuntime field classification). Tests must specify each
// field explicitly; there are no zero-value defaults that silently
// bypass real config.
//
// See SD-024 / TD-024 §Test config constructors and §Stage 3.
type TestBeadConfigOpts struct {
	Harness  string
	Model    string
	Provider string // CLI-only override, no durable home on AgentConfig
	ModelRef string // CLI-only override, no durable home on AgentConfig
	Effort   string // CLI-only override, no durable home on AgentConfig
	Mirror   *ExecutionsMirrorConfig
}

// NewTestConfigForBead returns a *Config that, when Resolve()d with
// the matching CLIOverrides, produces a ResolvedConfig whose
// execute-bead-relevant accessors return the values supplied in opts.
// Pure CLI-override fields (Provider, ModelRef, Effort) have no
// durable home on AgentConfig and must be applied at Resolve time via
// CLIOverrides.
func NewTestConfigForBead(opts TestBeadConfigOpts) *Config {
	cfg := &Config{
		Version: "1.0",
		Agent: &AgentConfig{
			Harness: opts.Harness,
			Model:   opts.Model,
		},
	}
	if opts.Mirror != nil {
		cfg.Executions = &ExecutionsConfig{Mirror: opts.Mirror}
	}
	return cfg
}

// TestBeadOverrides returns the CLIOverrides that, combined with the
// *Config produced by NewTestConfigForBead(opts), drive a Resolve call
// to a ResolvedConfig matching opts. Pure-override fields (Provider,
// ModelRef, Effort) have no durable home on *Config; they are applied
// at Resolve time only.
func TestBeadOverrides(opts TestBeadConfigOpts) CLIOverrides {
	return CLIOverrides{
		Provider: opts.Provider,
		ModelRef: opts.ModelRef,
		Effort:   opts.Effort,
	}
}

// TestLoopOverrides returns the CLIOverrides that, combined with the
// *Config produced by NewTestConfigForLoop(opts), drive a Resolve call
// to a ResolvedConfig matching opts. Pure-override fields (Assignee,
// Profile, MinTier, MaxTier) have no durable home on *Config; they are
// applied at Resolve time only.
func TestLoopOverrides(opts TestLoopConfigOpts) CLIOverrides {
	return CLIOverrides{
		Assignee: opts.Assignee,
		Profile:  opts.Profile,
		MinTier:  opts.MinTier,
		MaxTier:  opts.MaxTier,
	}
}

package cmd

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"github.com/DocumentDrivenDX/ddx/internal/config"
	"github.com/fatih/color"
	"github.com/spf13/cobra"
	"gopkg.in/yaml.v3"
)

// Command registration is now handled by command_factory.go
// This file only contains the run function implementation

// runConfig implements the config command logic for CommandFactory
func (f *CommandFactory) runConfig(cmd *cobra.Command, args []string) error {
	// Extract flags from cobra.Command
	showFlag, _ := cmd.Flags().GetBool("show")
	showFilesFlag, _ := cmd.Flags().GetBool("show-files")
	editFlag, _ := cmd.Flags().GetBool("edit")
	resetFlag, _ := cmd.Flags().GetBool("reset")
	wizardFlag, _ := cmd.Flags().GetBool("wizard")
	validateFlag, _ := cmd.Flags().GetBool("validate")
	globalFlag, _ := cmd.Flags().GetBool("global")

	// Handle flags by calling pure business logic functions
	if showFlag {
		return fmt.Errorf("config show removed - use 'cat .ddx/config.yaml' to view configuration")
	}

	if showFilesFlag {
		files := configListFiles(f.WorkingDir)
		return f.outputConfigFiles(cmd, files)
	}

	if editFlag {
		configPath := configGetPath(f.WorkingDir, globalFlag)
		return f.editConfigFile(cmd, configPath)
	}

	if resetFlag {
		configPath := configGetPath(f.WorkingDir, globalFlag)
		if err := configReset(f.WorkingDir, globalFlag); err != nil {
			return err
		}
		_, _ = fmt.Fprintf(cmd.OutOrStdout(), "✅ Configuration reset to defaults: %s\n", configPath)
		return nil
	}

	if wizardFlag {
		cfg, err := configWizard()
		if err != nil {
			return err
		}
		if err := configSave(f.WorkingDir, cfg, false); err != nil {
			return err
		}
		_, _ = fmt.Fprintln(cmd.OutOrStdout(), "✅ Configuration saved to .ddx/config.yaml")
		return nil
	}

	if validateFlag {
		if err := configValidate(f.WorkingDir); err != nil {
			return err
		}
		_, _ = fmt.Fprintln(cmd.OutOrStdout(), "✅ Configuration is valid")
		return nil
	}

	// Handle subcommands
	if len(args) == 0 {
		// Default behavior: show help
		return cmd.Help()
	}

	subcommand := args[0]
	switch subcommand {
	case "get":
		if len(args) < 2 {
			return fmt.Errorf("key required for get command")
		}
		value, err := configGet(f.WorkingDir, args[1], globalFlag)
		if err != nil {
			return err
		}
		_, _ = fmt.Fprintln(cmd.OutOrStdout(), value)
		return nil
	case "set":
		if len(args) < 3 {
			return fmt.Errorf("key and value required for set command")
		}
		if err := configSet(f.WorkingDir, args[1], args[2], globalFlag); err != nil {
			return err
		}
		_, _ = fmt.Fprintf(cmd.OutOrStdout(), "✅ Set %s = %s\n", args[1], args[2])
		return nil
	case "validate":
		if err := configValidate(f.WorkingDir); err != nil {
			return err
		}
		_, _ = fmt.Fprintln(cmd.OutOrStdout(), "✅ Configuration is valid")
		return nil
	case "export":
		// Simply output the config file content
		var configPath string
		if globalFlag {
			// Use global config path
			homeDir, err := os.UserHomeDir()
			if err != nil {
				return fmt.Errorf("failed to get home directory: %w", err)
			}
			configPath = filepath.Join(homeDir, ".ddx", "config.yaml")
		} else {
			// Use local config path
			configPath = filepath.Join(f.WorkingDir, ".ddx", "config.yaml")
		}

		content, err := os.ReadFile(configPath)
		if err != nil {
			return fmt.Errorf("failed to read config file: %w", err)
		}
		_, _ = fmt.Fprint(cmd.OutOrStdout(), string(content))
		return nil
	case "import":
		// For now, just read from stdin
		return fmt.Errorf("import not yet implemented")
	case "profile":
		if len(args) < 2 {
			return fmt.Errorf("profile subcommand requires additional arguments")
		}
		return f.handleProfileSubcommand(cmd, args[1:])
	default:
		return fmt.Errorf("unknown config subcommand: %s", subcommand)
	}
}

// Business Logic Layer - Pure Functions

// configGet retrieves a configuration value
func configGet(workingDir string, key string, global bool) (string, error) {
	var cfg *config.Config
	var err error

	if workingDir != "" && !global {
		// Load config from specific working directory using new format
		cfg, err = config.LoadWithWorkingDir(workingDir)
		if err != nil {
			return "", fmt.Errorf("failed to load configuration from %s: %w", workingDir, err)
		}
	} else {
		// Use standard config loading (current directory)
		cfg, err = config.Load()
		if err != nil {
			return "", fmt.Errorf("failed to load configuration: %w", err)
		}
	}

	return extractConfigValue(cfg, key)
}

// configSet sets a configuration value
func configSet(workingDir string, key, value string, global bool) error {
	var cfg *config.Config
	var err error

	if workingDir != "" && !global {
		// Load config from specific working directory using new format
		cfg, err = config.LoadWithWorkingDir(workingDir)
		if err != nil {
			// If file doesn't exist in working dir, create a new config
			if os.IsNotExist(err) {
				cfg = &config.Config{
					Version: "1.0",
					Library: &config.LibraryConfig{
						Path: ".ddx/plugins/ddx",
						Repository: &config.RepositoryConfig{
							URL:    "https://github.com/DocumentDrivenDX/ddx-library",
							Branch: "main",
						},
					},
				}
			} else {
				return fmt.Errorf("failed to load configuration from %s: %w", workingDir, err)
			}
		}
	} else {
		// Use standard config loading (current directory)
		cfg, err = config.Load()
		if err != nil {
			return fmt.Errorf("failed to load configuration: %w", err)
		}
	}

	if err := setConfigValueInStruct(cfg, key, value); err != nil {
		return err
	}

	return configSave(workingDir, cfg, global)
}

// configValidate validates the configuration
func configValidate(workingDir string) error {
	var cfg *config.Config
	var err error
	if workingDir != "" {
		cfg, err = config.LoadWithWorkingDir(workingDir)
	} else {
		cfg, err = config.Load()
	}
	if err != nil {
		return fmt.Errorf("failed to load configuration: %w", err)
	}

	return cfg.Validate()
}

// configReset resets configuration to defaults
func configReset(workingDir string, global bool) error {
	cfg := config.DefaultConfig
	return configSave(workingDir, cfg, global)
}

// configWizard runs the configuration wizard
func configWizard() (*config.Config, error) {
	cyan := color.New(color.FgCyan)
	_, _ = cyan.Println("🧙 DDx Configuration Wizard")
